```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <netinet/tcp.h>
#include <arpa/inet.h>
#include <unistd.h>

/**
 * Sets various TCP socket options for either low latency or maximum throughput.
 * 
 * @param sockfd The socket file descriptor.
 * @param low_latency If set to 1, the function will configure the socket for low latency;
 *                    otherwise, it will be configured for maximum throughput.
 * @return 0 on success, or -1 on error with errno set appropriately.
 */
int set_socket_options(int sockfd, int low_latency) {
    int optval;

    // Set the IP_TOS option to either minimize delay or maximize throughput.
    optval = low_latency ? IPTOS_LOWDELAY : IPTOS_THROUGHPUT;
    if (setsockopt(sockfd, IPPROTO_IP, IP_TOS, &optval, sizeof(optval)) < 0) {
        perror("setsockopt IP_TOS failed");
        return -1;
    }

    // Set or unset TCP_NODELAY based on the low_latency parameter.
    optval = low_latency ? 1 : 0;
    if (setsockopt(sockfd, IPPROTO_TCP, TCP_NODELAY, &optval, sizeof(optval)) < 0) {
        perror("setsockopt TCP_NODELAY failed");
        return -1;
    }

    // For Linux: Set or unset the TCP_CORK option based on the low_latency parameter.
#ifdef TCP_CORK
    optval = low_latency ? 0 : 1;
    if (setsockopt(sockfd, IPPROTO_TCP, TCP_CORK, &optval, sizeof(optval)) < 0) {
        perror("setsockopt TCP_CORK failed");
        return -1;
    }
#endif

    // For BSD: Set or unset the TCP_NOPUSH option based on the low_latency parameter.
#ifdef TCP_NOPUSH
    optval = low_latency ? 0 : 1;
    if (setsockopt(sockfd, IPPROTO_TCP, TCP_NOPUSH, &optval, sizeof(optval)) < 0) {
        perror("setsockopt TCP_NOPUSH failed");
        return -1;
    }
#endif

    // Set or unset TCP_QUICKACK based on the low_latency parameter.
    // Note: Other parts of your application may need to reset this option as necessary.
    optval = low_latency ? 1 : 0;
    if (setsockopt(sockfd, IPPROTO_TCP, TCP_QUICKACK, &optval, sizeof(optval)) < 0) {
        perror("setsockopt TCP_QUICKACK failed");
        return -1;
    }

    return 0;
}

int main() {
    int sockfd;

    // Create a socket here (AF_INET and SOCK_STREAM).

    // ...

    // Now let's call our function. Set '1' for low latency, or '0' for maximum throughput.
    if (set_socket_options(sockfd, 1) != 0) {
        // Handle error
        close(sockfd);
        exit(EXIT_FAILURE);
    }

    // Use the configured socket.

    close(sockfd);
    return 0;
}
```

Explanation of options based on `low_latency` flag:
- `IPTOS_LOWDELAY`: Used to minimize delays for interactive traffic.
- `IPTOS_THROUGHPUT`: Used to optimize throughput.

- `TCP_NODELAY`: If `low_latency` is set, this option is enabled to ensure data is sent immediately.
- `TCP_CORK` and `TCP_NOPUSH`: If `low_latency` is not set, these options are enabled to maximize throughput by waiting to send full-sized packets.
- `TCP_QUICKACK`: Enabling this can help reduce acknowledgment latency when interactive traffic is preferred.

