/**
 * Sets the TCP socket options for either low latency or high throughput.
 *
 * @param sockfd The socket file descriptor.
 * @param optimize_for_latency If nonzero, optimize for low latency; otherwise, optimize for throughput.
 * @return 0 on success, or -1 on error with errno set by the failing setsockopt call.
 */
int optimize_socket(int sockfd, int optimize_for_latency) {
    int optval;
    int result;

    // Set the IP_TOS option to either minimize delay or maximize throughput.
    optval = optimize_for_latency ? IPTOS_LOWDELAY : IPTOS_THROUGHPUT;
    result = setsockopt(sockfd, IPPROTO_IP, IP_TOS, &optval, sizeof(optval));
    if (result < 0) {
        perror("Error setting IP_TOS");
        return -1;
    }

    // Enable or disable Nagle's algorithm (TCP_NODELAY).
    optval = optimize_for_latency ? 1 : 0;
    result = setsockopt(sockfd, IPPROTO_TCP, TCP_NODELAY, &optval, sizeof(optval));
    if (result < 0) {
        perror("Error setting TCP_NODELAY");
        return -1;
    }

    // Enable or disable TCP_CORK (Linux specific) or TCP_NOPUSH (BSD specific),
    // depending on whether we want to optimize for latency or throughput.
#ifdef TCP_CORK
    optval = optimize_for_latency ? 0 : 1; // Enable CORK for throughput, disable for latency.
    result = setsockopt(sockfd, IPPROTO_TCP, TCP_CORK, &optval, sizeof(optval));
    if (result < 0) {
        perror("Error setting TCP_CORK");
        return -1;
    }
#elif defined(TCP_NOPUSH)
    optval = optimize_for_latency ? 0 : 1; // Enable NOPUSH for throughput, disable for latency.
    result = setsockopt(sockfd, IPPROTO_TCP, TCP_NOPUSH, &optval, sizeof(optval));
    if (result < 0) {
        perror("Error setting TCP_NOPUSH");
        return -1;
    }
#endif

    // TCP_QUICKACK is not typically used for throughput optimization, only for latency.
    // So it’s set only when low latency is desired.
    if (optimize_for_latency) {
        optval = 1;
        result = setsockopt(sockfd, IPPROTO_TCP, TCP_QUICKACK, &optval, sizeof(optval));
        if (result < 0) {
            perror("Error setting TCP_QUICKACK");
            return -1;
        }
    }

    return 0; // All options set successfully.
}

int main() {
    // We'll use an example IP and port for creating a socket.
    const char *server_ip = "127.0.0.1";
    uint16_t port = 8080;

    // Create a TCP socket.
    int sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd < 0) {
        perror("Socket creation failed");
        exit(EXIT_FAILURE);
    }

    // Connect the socket to the server for demonstration purposes.
    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(port);
    inet_pton(AF_INET, server_ip, &server_addr.sin_addr);

    if (connect(sockfd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("Connect failed");
        close(sockfd);
        exit(EXIT_FAILURE);
    }

    // Now let's call our function to set the socket options.
    // Pass a nonzero value to optimize for low latency, or 0 for high throughput.
    if (optimize_socket(sockfd, 1) < 0) {
        // An error occurred while setting the options.
        close(sockfd);
        exit(EXIT_FAILURE);
    }

    // The socket is now configured. You can now use the socket to send and receive data.

    // Clean up.
    close(sockfd);
    return 0;
}
